VALUES
  ('disabled-57f41407-moex-00056', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於民事訴訟事件訴訟救助聲請准否之判斷，下列敘述何者錯誤？', '["必要共同訴訟人聲請訴訟救助，必全體當事人均無資力，始足當之", "關於無資力支出訴訟費用之事由，應由聲請人提出可使法院信其主張為 真實並能即時調查之證據", "所謂無資力，係指窘於生活，且缺乏經濟上之信用者而言", "是否顯無獲得勝訴之望，係指法院就當事人主張之事實，經調查辯論， 認定其應受敗訴之裁判者而言"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00057', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '法院對前已依公示送達之當事人，欲再為公示送達時，如以於司法院網站 公告為公示送達方式，該送達自公告日起幾日發生效力？', '["60日", "30日", "20日", "翌日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00058', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '民事訴訟法第209條規定：「法院調查證據，除別有規定外，於言詞辯論 期日行之。」此為下列何種原則之具體規定？', '["自由心證主義", "公開審理主義", "直接審理主義", "訴訟經濟原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00059', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於自由心證主義，下列敘述何者錯誤？', '["法院依自由心證判斷事實真偽時，應斟酌全辯論意旨與調查證據之結果", "自由心證不得違反經驗法則與論理法則", "作為自由心證主義審酌對象之全辯論意旨，係指言詞辯論時所出現之一切 資料而言，故當事人或代理人之陳述態度如何，亦屬法院得斟酌之事項", "原告所提之證據，不得作為有利於被告認定之用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00060', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何者非屬民事訴訟關於通常訴訟程序起訴狀應表明之事項？', '["當事人", "引用之證據及其內容", "訴訟標的及其原因事實", "應受判決事項之聲明"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00061', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於訴之變更或追加，下列敘述何者錯誤？', '["所謂訴之變更，係指原告於起訴後，提起新訴以「代替」原訴", "所謂訴之追加，係指原告於起訴後，提起新訴以「合併」於原訴", "訴之變更、追加，須向原訴繫屬之法院為之", "如變更或追加之新訴係專屬他法院管轄者，除經被告同意外，不得為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00062', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於民事訴訟確定判決之既判力，下列敘述何者錯誤？', '["就原告主張之訴訟標的經法院裁判者，發生既判力", "主張抵銷之請求，其成立與否經裁判者，以主張抵銷之額為限，有既判力", "既判力及於所有的攻擊、防禦方法之判斷", "為他人而為原告或被告者之確定判決，既判力擴張及於該他人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00063', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於調解程序，下列敘述何者錯誤？', '["調解程序由法官選任調解委員1人至3人先行調解，當事人也可以合意 請求法官直接調解", "為了達成調解目的之必要，法院得依當事人聲請，禁止他造處分標的物 或命為其他一定行為或不行為。該部分處置在調解程序終結時失其效力", "調解程序必要時得不公開", "只要是就調解事件有利害關係的第三人，不經法官許可，就可以直接參 加調解程序"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00064', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於簡易訴訟程序之第二審裁判，下列敘述何者錯誤？', '["對於簡易訴訟程序之第二審確定終局裁判，有足以影響裁判之重要證 物，漏未斟酌者，亦得提起再審之訴或聲請再審", "對於簡易訴訟程序之裁判，逕向最高法院提起上訴或抗告，經以上訴或 抗告無理由為駁回之裁判者，就不得更以同一理由提起再審之訴或聲請 再審", "對於簡易訴訟程序之第二審裁判，提起第三審上訴或抗告，須經原裁判 法院之許可", "對於簡易訴訟程序之第二審裁判，提起第三審上訴或抗告，只要表明上 訴或抗告意思即可，不需表明上訴或抗告理由"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00065', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '對於小額程序之第一審裁判不服，其救濟方式為何？', '["上訴或抗告於管轄之地方法院，其審判以合議行之", "上訴或抗告於管轄之地方法院，其審判以獨任法官行之", "上訴或抗告於管轄之高等法院，其審判以獨任法官行之", "上訴或抗告於管轄之高等法院，其審判以合議行之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
